 1	import type { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { Button, ButtonVariant } from '@patternfly/react-core';
 5	import { ForkliftTrans, useForkliftTranslation } from '@utils/i18n';
 6	
 7	import type { PlanConditionType } from '../utils/constants';
 8	import { getTroubleshootMessage } from '../utils/utils';
 9	
10	type TroubleshootMessageProps = {
11	  planURL: string;
12	  type: PlanConditionType;
13	};
14	
15	const TroubleshootMessage: FC<TroubleshootMessageProps> = ({ planURL, type }) => {
16	  const { t } = useForkliftTranslation();
17	  const navigate = useNavigate();
18	
19	  if (getTroubleshootMessage(type)) {
20	    return (
21	      <ForkliftTrans>
22	        To troubleshoot, check and edit your plan{' '}
23	        <Button
24	          isInline
25	          variant={ButtonVariant.link}
26	          onClick={() => {
27	            navigate(`${planURL}/mappings`);
28	          }}
29	        >
30	          mappings
31	        </Button>
32	        .
33	      </ForkliftTrans>
34	    );
35	  }
36	
37	  return <>{t('To troubleshoot, check the Forklift controller pod logs.')}</>;
38	};
39	
40	export default TroubleshootMessage;

